/* Goldilocks field + NTT in WebAssembly (Rust, wasm/goldilocks/) — bit-identical to static/stark/field.js.
 * Moves the STARK prover's NTTs off BigInt for a large speedup (esp. on phones). Shared static BUF; the
 * prover is single-threaded so calls are sequential. */
const WASM_B64 = "";
let _g = null;
function _decode(b64) {
  if (typeof atob !== "undefined") return Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
  return Uint8Array.from(Buffer.from(b64, "base64"));
}
export async function initGoldilocksWasm() {
  if (_g) return _g;
  const { instance } = await WebAssembly.instantiate(_decode(WASM_B64));
  const { memory, buf_ptr, ntt, scale } = instance.exports;
  const NMAX = 8192, ptr = buf_ptr();
  const view = new BigUint64Array(memory.buffer, ptr, NMAX);   // static BUF -> memory never grows -> view stable
  _g = { ntt, scale, view, NMAX };
  return _g;
}
